/**
 * Returns a shuffled copy of an array using the Fisher-Yates algorithm.
 * The optional random function makes the logic easier to unit test.
 *
 * @param {Array} items - Items to shuffle.
 * @param {Function} random - Random number generator.
 * @returns {Array} A new shuffled array.
 */
export default function shuffle(items, random = Math.random) {
  if (!Array.isArray(items)) {
    throw new TypeError("shuffle expects an array");
  }

  const shuffledItems = [...items];

  for (let index = shuffledItems.length - 1; index > 0; index -= 1) {
    const randomIndex = Math.floor(random() * (index + 1));
    [shuffledItems[index], shuffledItems[randomIndex]] = [
      shuffledItems[randomIndex],
      shuffledItems[index]
    ];
  }

  return shuffledItems;
}
