import shuffle from "./Shuffle.js";
import {
  clearElement,
  createElement,
  getTrimmedValue,
  setError
} from "./utilityRenderFunctions.js";

const storageKey = "study-night-card-sets";

const state = {
  sets: loadSets(),
  selectedSetId: null
};

const elements = {
  pages: document.querySelectorAll(".page"),
  navButtons: document.querySelectorAll("[data-page]"),
  createSetForm: document.querySelector("#create-set-form"),
  createSetInput: document.querySelector("#set-name"),
  createSetError: document.querySelector("#create-set-error"),
  setList: document.querySelector("#set-list"),
  selectedSetTitle: document.querySelector("#selected-set-title"),
  selectedSetCount: document.querySelector("#selected-set-count"),
  addCardForm: document.querySelector("#add-card-form"),
  cardFrontInput: document.querySelector("#card-front"),
  cardBackInput: document.querySelector("#card-back"),
  addCardError: document.querySelector("#add-card-error"),
  cardsList: document.querySelector("#cards-list"),
  shuffleCardsButton: document.querySelector("#shuffle-cards"),
  clearDataButton: document.querySelector("#clear-data")
};

function loadSets() {
  const savedSets = localStorage.getItem(storageKey);

  if (!savedSets) {
    return [];
  }

  try {
    return JSON.parse(savedSets);
  } catch {
    return [];
  }
}

function saveSets() {
  localStorage.setItem(storageKey, JSON.stringify(state.sets));
}

function createId(prefix) {
  return `${prefix}-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function getSelectedSet() {
  return state.sets.find((set) => set.id === state.selectedSetId) || null;
}

function showPage(pageName) {
  elements.pages.forEach((page) => {
    page.classList.toggle("pageVisible", page.id === `${pageName}-page`);
  });

  elements.navButtons.forEach((button) => {
    button.classList.toggle("active", button.dataset.page === pageName);
  });
}

function renderSets() {
  clearElement(elements.setList);

  if (state.sets.length === 0) {
    elements.setList.append(
      createElement("p", {
        className: "emptyState",
        textContent: "No card sets yet. Create your first set above.",
        attributes: {
          "data-cy": "empty-set-list"
        }
      })
    );
    return;
  }

  state.sets.forEach((set) => {
    const button = createElement("button", {
      className: `setButton${set.id === state.selectedSetId ? " active" : ""}`,
      textContent: `${set.name} (${set.cards.length})`,
      attributes: {
        type: "button",
        "data-cy": "set-item"
      }
    });

    button.addEventListener("click", () => {
      state.selectedSetId = set.id;
      renderApp();
    });

    elements.setList.append(button);
  });
}

function renderSelectedSet() {
  const selectedSet = getSelectedSet();

  clearElement(elements.cardsList);

  if (!selectedSet) {
    elements.selectedSetTitle.textContent = "No set selected";
    elements.selectedSetCount.textContent = "Create or select a set to begin.";
    elements.shuffleCardsButton.disabled = true;
    elements.addCardForm
      .querySelectorAll("input, textarea, button")
      .forEach((input) => {
        input.disabled = true;
      });
    elements.cardsList.append(
      createElement("p", {
        className: "emptyState",
        textContent: "Your cards will appear here after you select a set.",
        attributes: {
          "data-cy": "no-selected-set"
        }
      })
    );
    return;
  }

  elements.selectedSetTitle.textContent = selectedSet.name;
  elements.selectedSetCount.textContent = `${selectedSet.cards.length} card(s) in this set.`;
  elements.shuffleCardsButton.disabled = selectedSet.cards.length < 2;
  elements.addCardForm
    .querySelectorAll("input, textarea, button")
    .forEach((input) => {
      input.disabled = false;
    });

  if (selectedSet.cards.length === 0) {
    elements.cardsList.append(
      createElement("p", {
        className: "emptyState",
        textContent: "No cards yet. Add the first one using the form above.",
        attributes: {
          "data-cy": "empty-card-list"
        }
      })
    );
    return;
  }

  selectedSet.cards.forEach((card, index) => {
    const cardElement = createElement("article", {
      className: "studyCard",
      attributes: {
        "data-cy": "study-card"
      },
      children: [
        createElement("h3", {
          textContent: `${index + 1}. ${card.front}`,
          attributes: {
            "data-cy": "card-front-text"
          }
        }),
        createElement("p", {
          textContent: card.back,
          attributes: {
            "data-cy": "card-back-text"
          }
        })
      ]
    });

    elements.cardsList.append(cardElement);
  });
}

function renderApp() {
  renderSets();
  renderSelectedSet();
}

function handleCreateSet(event) {
  event.preventDefault();

  const setName = getTrimmedValue(elements.createSetInput);

  if (!setName) {
    setError(elements.createSetError, "Set name is required.");
    return;
  }

  const newSet = {
    id: createId("set"),
    name: setName,
    cards: []
  };

  state.sets.push(newSet);
  state.selectedSetId = newSet.id;
  saveSets();

  elements.createSetInput.value = "";
  setError(elements.createSetError, "");
  renderApp();
}

function handleAddCard(event) {
  event.preventDefault();

  const selectedSet = getSelectedSet();

  if (!selectedSet) {
    setError(elements.addCardError, "Select a set before adding cards.");
    return;
  }

  const front = getTrimmedValue(elements.cardFrontInput);
  const back = getTrimmedValue(elements.cardBackInput);

  if (!front || !back) {
    setError(
      elements.addCardError,
      "Both card front and card back are required."
    );
    return;
  }

  selectedSet.cards.push({
    id: createId("card"),
    front,
    back
  });

  saveSets();

  elements.cardFrontInput.value = "";
  elements.cardBackInput.value = "";
  setError(elements.addCardError, "");
  renderApp();
}

function handleShuffleCards() {
  const selectedSet = getSelectedSet();

  if (!selectedSet || selectedSet.cards.length < 2) {
    return;
  }

  selectedSet.cards = shuffle(selectedSet.cards);
  saveSets();
  renderApp();
}

function handleClearData() {
  state.sets = [];
  state.selectedSetId = null;
  saveSets();
  renderApp();
}

function registerEvents() {
  elements.navButtons.forEach((button) => {
    button.addEventListener("click", () => {
      showPage(button.dataset.page);
    });
  });

  elements.createSetForm.addEventListener("submit", handleCreateSet);
  elements.addCardForm.addEventListener("submit", handleAddCard);
  elements.shuffleCardsButton.addEventListener("click", handleShuffleCards);
  elements.clearDataButton.addEventListener("click", handleClearData);
}

registerEvents();
showPage("home");
renderApp();
